INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('field3d_new_reveal_cue_missing_from_devstatemeta_maxreveal', 'A new timed reveal cue (potential.show_field_lines_cross_shells.at_ms) was added to the renderer but not to deriveStateMeta.maxRevealForField3dState, so THE EYE pinned PM_simTimeMs before the reveal and photographed an empty STATE_4 — the field lines (the PRIMARY aha) never appeared in the frozen frame though the renderer code was correct', 'CRITICAL', 'peter_parker:renderer_primitives', 'maxRevealForField3dState derives the frozen-frame pin time only from known *_at_ms cues; an unrecognised new cue leaves the pin at DEFAULT_REVEAL_MS (1500), before the reveal (at_ms 9500). The renderer fade fcF=(ms-at_ms)/700 stays 0 -> opacity 0 -> invisible. tsc + validate:concepts pass; only THE EYE frozen frame reveals it.', 'Every new field_3d timed reveal cue (any *_at_ms / *_duration_ms the renderer animates on PM_simTimeMs) MUST be registered in deriveStateMeta.maxRevealForField3dState (and classified in deriveHoldExpectations) in the SAME change, or THE EYE pins the frozen frame before the payoff and false-negatives the reveal.', 'manual', 'Read STATE_N__frozen.png for any state declaring a new *_at_ms reveal cue; confirm the revealed element is visibly rendered. The frozen frame is pinned to maxRevealForField3dState(state) — if the element is absent, the cue is not registered there.', 'FIXED', ARRAY['equipotential_surfaces'], ARRAY['src/lib/renderers/field_3d_renderer.ts', 'src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-28_equipotential_surfaces_fixes', 'incident'),
('field3d_pool_element_visibility_must_match_visible_elements_token', 'A per-frame-driven pool of objects (the cross-shell field-line ArrowHelpers) tagged with a private elementType the state-apply matcher could not substring-match against the visible_elements token, so the generic matcher set visible=false on entry and the frame loop fought it', 'MAJOR', 'peter_parker:renderer_primitives', 'The generic visible_elements matcher in applyState substring-matches userData.elementType/id against the state tokens. elementType "pm_cross_line" never matched the JSON token "field_lines_cross_shells", so on entry the matcher forced visible=false.', 'A field_3d pool whose visibility is owned by a per-state apply/frame function must EITHER carry an elementType that substring-matches the JSON visible_elements token, OR be fully driven (visible writes) by the authoritative apply+frame functions that run after the generic matcher. Prefer matching the token so the two agree.', 'manual', 'For any pool element gated on a visible_elements token, confirm its userData.elementType (or id) substring-contains that token; otherwise the generic matcher hides it on state entry.', 'FIXED', ARRAY['equipotential_surfaces'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-28_equipotential_surfaces_fixes', 'incident'),
('field3d_per_state_override_must_drive_both_apply_and_frame_loops', 'A per-state shells_override that toggled which shell spheres show but left the global V-label sprites in place — the STATE_6 frame loop re-revealed every isPmShell label every frame, leaking the global V=12/8/6/4 over the override values', 'MODERATE', 'peter_parker:renderer_primitives', 'The override was honoured in applyPotentialMeaningState but the per-frame STATE_6 shells block iterated all isPmShell objects setting visible=true unconditionally, re-showing the global labels the apply step had hidden.', 'A per-state config override that changes element visibility/text MUST be applied in BOTH the per-state apply function AND every per-frame loop that touches the same elements; a frame loop that unconditionally re-reveals a shared pool defeats the apply-step override. Null/absent override path must reproduce the original behaviour byte-for-byte.', 'manual', 'Read STATE_N__frozen.png for a state with a shells_override; confirm only the override labels/radii render (no stale global labels). Read a state WITHOUT override; confirm the global shells render unchanged.', 'FIXED', ARRAY['equipotential_surfaces'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-28_equipotential_surfaces_fixes', 'incident'),
('field3d_sign_flip_must_not_be_gated_on_formula_sibling_flag', 'The potential sign-flip block was gated on isFormulaPC (config.v_vs_r_curve present), so a sign_flip-using concept WITHOUT a v_vs_r_curve (equipotential_surfaces) never recolored shells / prepended negative V labels in STATE_6', 'MAJOR', 'peter_parker:renderer_primitives', 'if (isFormulaPC && p.show_sign_flip) — isFormulaPC is false for a concept with no v_vs_r_curve, so the block was skipped even though the state set show_sign_flip.', 'A per-state behaviour gate must key on the per-state flag that requests it (p.show_sign_flip), never on a sibling-concept config marker (isFormulaPC). For concepts that DO carry the marker the change must be a no-op (verify the sibling unchanged).', 'manual', 'Read STATE_N__frozen.png for a state with show_sign_flip + sign_flip_at_ms; confirm shells recolor and V labels read negative. Confirm the v_vs_r_curve sibling (electric_potential_point_charge) STATE_5 sign-flip is unchanged.', 'FIXED', ARRAY['equipotential_surfaces'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-28_equipotential_surfaces_fixes', 'incident')
